func solve(nums []int64, queries [][]int64) int64 {
    MOD := 1000000007
    for _, query := range queries {
        li := query[0]
        ri := query[1]
        ki := query[2]
        vi := query[3]
        idx := li
        for idx <= ri {
            nums[idx] = (nums[idx] * vi) % MOD
            idx += ki
        }
    }
    xorResult := int64(0)
    for _, num := range nums {
        xorResult ^= num
    }
    return xorResult
}
